const finalizarViagem = async () => {
  try {
    const viagemData = {
      ...formData,
      abastecimentos,
      oficinas,
      pedagios,
      outros,
      resumo: {
        totalBruto: precoTotal,
        totalGastos,
        totalLiquido
      }
    };

    try {
      // Tenta salvar no backend
      await api.post('/viagens', viagemData);
      alert('Viagem salva com sucesso!');
    } catch (error) {
      console.log('Salvando localmente (backend não disponível)');
      // Salva no localStorage para simular persistência
      const viagensSalvas = JSON.parse(localStorage.getItem('@App:viagens') || '[]');
      const novaViagem = {
        ...viagemData,
        id: Date.now(),
        data_entrada: viagemData.dataInicio,
        data_chegada: viagemData.dataFim,
        km_entrada: viagemData.kmChegada,
        cidade_saida: cidades.find(c => c.id == viagemData.cidadeSaida)?.cidade || 'Cidade',
        cidade_chegada: cidades.find(c => c.id == viagemData.cidadeChegada)?.cidade || 'Cidade'
      };
      viagensSalvas.push(novaViagem);
      localStorage.setItem('@App:viagens', JSON.stringify(viagensSalvas));
      alert('Viagem salva localmente! (modo demonstração)');
    }
    
    navigate('/home');
  } catch (error) {
    console.error('Erro ao salvar viagem:', error);
    alert('Erro ao salvar viagem. Tente novamente.');
  }
};
